// Parse inputs with defaults. Supports date_from, date_to (ISO dates), and lookback_days.
const body = $input.first().json.body || {};
const now = new Date();
const lookbackDays = body.lookback_days != null ? Number(body.lookback_days) : 30;

let dateFrom, dateTo;
if (body.date_from) {
  dateFrom = new Date(body.date_from);
} else {
  dateFrom = new Date(now.getTime() - lookbackDays * 24 * 60 * 60 * 1000);
}
if (body.date_to) {
  dateTo = new Date(body.date_to);
} else {
  dateTo = now;
}

return [{
  json: {
    date_from: dateFrom.toISOString().slice(0, 10),
    date_to: dateTo.toISOString().slice(0, 10),
    lookback_days: lookbackDays,
  },
}];

// ===== Pair detection + same-side dupe collapse =====
// Mirrors tools/meeting_federation/pair_meetings.py

const WINDOW_MIN = 10;
const SAME_SIDE_DUPE_WINDOW_MIN = 5;
const TITLE_TOKEN_MIN = 1;

const STOPWORDS = new Set(['and','or','the','a','an','to','of','for','with','on','in','at','vs','v','via','by','from','into','about','meeting','call','sync','intro','introduction','connect','catch','up','touch','base','follow','followup','discussion','chat','review','update','kickoff','updated','new','weekly','monthly','daily','quarterly','1on1','1-1','11','team','internal','external','zero','rfi','sample_company','0rfi']);
const NAME_DROP = new Set(['Sales User','Sales User','Executive','Stakeholder']);

function tokenize(t) {
  if (!t) return new Set();
  const cleaned = t.toLowerCase().replace(/[^a-z0-9 ]+/g, ' ');
  const toks = cleaned.split(/\s+/).filter(Boolean);
  return new Set(toks.filter(x => x.length > 1 && !STOPWORDS.has(x) && !NAME_DROP.has(x)));
}

function setIntersect(a, b) {
  const out = new Set();
  for (const x of a) if (b.has(x)) out.add(x);
  return out;
}

function parseProp(prop) {
  if (!prop) return null;
  if (prop.type === 'title') return (prop.title || []).map(x => x.plain_text || '').join('');
  if (prop.type === 'rich_text') return (prop.rich_text || []).map(x => x.plain_text || '').join('');
  if (prop.type === 'date') return prop.date ? prop.date.start : null;
  if (prop.type === 'url') return prop.url;
  if (prop.type === 'select') return prop.select ? prop.select.name : null;
  if (prop.type === 'multi_select') return (prop.multi_select || []).map(x => x.name);
  return null;
}

function normalizeNotionPage(page, side) {
  const props = page.properties || {};
  const title = parseProp(props['Meeting']) || '(untitled)';
  const startTime = parseProp(props['Start Time']) || parseProp(props['Date']);
  const created = page.created_time;
  const attendees = parseProp(props['Attendees']) || '';
  const company = parseProp(props['Company']) || '';
  const meetingLink = parseProp(props['Meeting Link']) || '';
  const recordingUrl = parseProp(props['Recording URL']) || '';
  const tags = parseProp(props['Tags']) || [];
  const project = parseProp(props['Project']) || [];
  const status = parseProp(props['Status']) || '';
  const type = parseProp(props['Type']) || '';
  const start = startTime ? new Date(startTime) : null;
  const anchor = start || (created ? new Date(created) : null);
  return {
    side,
    id: page.id,
    title,
    start_iso: startTime,
    anchor_iso: anchor ? anchor.toISOString() : null,
    anchor_ms: anchor ? anchor.getTime() : null,
    anchor_source: start ? 'start' : (created ? 'created' : 'none'),
    attendees,
    company,
    meeting_link: meetingLink,
    recording_url: recordingUrl,
    tags,
    project,
    status,
    type,
    notion_url: page.url,
  };
}

function collapseDupes(rows) {
  const dated = rows.filter(r => r.anchor_ms != null).sort((a, b) => a.anchor_ms - b.anchor_ms);
  const undated = rows.filter(r => r.anchor_ms == null);
  const out = [];
  const used = new Set();
  const w = SAME_SIDE_DUPE_WINDOW_MIN * 60 * 1000;

  for (let i = 0; i < dated.length; i++) {
    const r = dated[i];
    if (used.has(r.id)) continue;
    const cluster = [r];
    used.add(r.id);
    const rTokens = tokenize(r.title);
    for (let j = i + 1; j < dated.length; j++) {
      const other = dated[j];
      if (used.has(other.id)) continue;
      if (other.anchor_ms - r.anchor_ms > w) break;
      const otherTokens = tokenize(other.title);
      if (rTokens.size > 0 && otherTokens.size > 0 && setIntersect(rTokens, otherTokens).size > 0) {
        cluster.push(other);
        used.add(other.id);
      }
    }
    const primary = { ...cluster[0] };
    if (cluster.length > 1) {
      primary.dupe_urls = cluster.slice(1).map(c => c.notion_url);
      primary.dupe_titles = cluster.slice(1).map(c => c.title);
    }
    out.push(primary);
  }

  const norm = t => (t || '').replace(/\s+/g, ' ').trim().toLowerCase();
  const kept = [];
  for (const u of undated) {
    const uNorm = norm(u.title);
    if (!uNorm) { kept.push(u); continue; }
    let matched = false;
    for (const d of out) {
      if (norm(d.title) === uNorm) {
        d.dupe_urls = (d.dupe_urls || []).concat([u.notion_url]);
        d.dupe_titles = (d.dupe_titles || []).concat([u.title]);
        matched = true;
        break;
      }
    }
    if (!matched) kept.push(u);
  }
  return out.concat(kept);
}

function pair(zr, re) {
  const pairs = [];
  const rejected = [];
  const zrColl = collapseDupes(zr);
  const reColl = collapseDupes(re);
  const zrDated = zrColl.filter(r => r.anchor_ms != null);
  const reDated = reColl.filter(r => r.anchor_ms != null);
  const zrUsed = new Set();
  const reUsed = new Set();
  const w = WINDOW_MIN * 60 * 1000;

  const reSorted = [...reDated].sort((a, b) => a.anchor_ms - b.anchor_ms);

  for (const reRow of reSorted) {
    if (reUsed.has(reRow.id)) continue;
    const candidates = zrDated.filter(z => !zrUsed.has(z.id) && Math.abs(z.anchor_ms - reRow.anchor_ms) <= w);
    if (candidates.length === 0) continue;
    const reNeighbors = reDated.filter(r => r.id !== reRow.id && !reUsed.has(r.id) && Math.abs(r.anchor_ms - reRow.anchor_ms) <= w);
    const crowded = candidates.length > 1 || reNeighbors.length > 0;

    if (!crowded) {
      const best = candidates[0];
      const deltaMin = Math.round(Math.abs(best.anchor_ms - reRow.anchor_ms) / 60000);
      pairs.push({ zr: best, re: reRow, basis: 'unique candidate in ±10 min window', confidence: 'high', delta_min: deltaMin });
      zrUsed.add(best.id);
      reUsed.add(reRow.id);
    } else {
      const reTokens = tokenize(reRow.title);
      const scored = candidates.map(c => {
        const overlap = setIntersect(reTokens, tokenize(c.title));
        return { c, overlap, n: overlap.size };
      }).sort((a, b) => (b.n - a.n) || (Math.abs(a.c.anchor_ms - reRow.anchor_ms) - Math.abs(b.c.anchor_ms - reRow.anchor_ms)));
      const top = scored[0];
      if (top.n >= TITLE_TOKEN_MIN) {
        const deltaMin = Math.round(Math.abs(top.c.anchor_ms - reRow.anchor_ms) / 60000);
        pairs.push({ zr: top.c, re: reRow, basis: `crowded window; title overlap = [${[...top.overlap].sort().join(', ')}]`, confidence: 'high', delta_min: deltaMin });
        zrUsed.add(top.c.id);
        reUsed.add(reRow.id);
      } else {
        rejected.push({ re: reRow, zr_candidates: scored.map(s => s.c), reason: 'crowded window; no shared title tokens' });
      }
    }
  }

  return {
    pairs,
    zr_unpaired: zrColl.filter(r => !zrUsed.has(r.id)),
    re_unpaired: reColl.filter(r => !reUsed.has(r.id)),
    rejected,
  };
}

// ===== Entry =====
const items = $input.all();
const zrPages = (items[0] && items[0].json && items[0].json.results) || [];
const rePages = (items[1] && items[1].json && items[1].json.results) || [];

const zr = zrPages.map(p => normalizeNotionPage(p, 'sample_company'));
const re = rePages.map(p => normalizeNotionPage(p, 'recall'));

const result = pair(zr, re);

return [{
  json: {
    query: $('Parse inputs').item.json,
    counts: {
      zr_raw: zr.length,
      re_raw: re.length,
      pairs: result.pairs.length,
      rejected: result.rejected.length,
      zr_unpaired: result.zr_unpaired.length,
      re_unpaired: result.re_unpaired.length,
    },
    pairs: result.pairs,
    rejected: result.rejected,
    unpaired_sample_company: result.zr_unpaired,
    unpaired_recall: result.re_unpaired,
    generated_at: new Date().toISOString(),
  },
}];
